import { getAdConnections, connectAdPlatform, disconnectAdPlatform, generateRetargetingOpportunities, estimateBudget, exportAudienceCSV, downloadCSV } from '../services/retargeting';
```

Add state variables to the component:
```typescript
const [schedules, setSchedules] = useState<MonitoringSchedule[]>([]);
const [scanHistory, setScanHistory] = useState<ScheduledScanResult[]>([]);
const [schedFreq, setSchedFreq] = useState<ScheduleFrequency>('daily');
const [schedHour, setSchedHour] = useState('09:00');
const [schedDay, setSchedDay] = useState(1);
const [schedEmail, setSchedEmail] = useState(false);
// Retargeting state
const [resultTab, setResultTab] = useState<'overview' | 'retargeting'>('overview');
const [adConnections, setAdConnections] = useState<AdConnection[]>([]);
const [connectingPlatform, setConnectingPlatform] = useState<AdPlatform | null>(null);
const [retargetingOpps, setRetargetingOpps] = useState<RetargetingOpportunity[]>([]);
const [budgetPlatform, setBudgetPlatform] = useState<AdPlatform>('google-ads');
const [dailyBudget, setDailyBudget] = useState(50);
const [expandedPixel, setExpandedPixel] = useState<string | null>(null);
const [copiedPixel, setCopiedPixel] = useState<string | null>(null);
```

Add useEffect to load schedules on mount:
```typescript
useEffect(() => {
  setSchedules(getSchedules());
  setScanHistory(getScheduledHistory());
  const pending = checkAndRunPendingScans();
  if (pending.length > 0) {
    setScanHistory(getScheduledHistory());
    setSchedules(getSchedules());
  }
}, []);
```

Add useEffect to generate retargeting when result changes:
```typescript
useEffect(() => {
  if (result) {
    setAdConnections(getAdConnections());
    setRetargetingOpps(generateRetargetingOpportunities(result.citations));
  }
}, [result]);
```

