  1→import type {
  2→  MonitoringSchedule,
  3→  ScheduleFrequency,
  4→  ScheduledScanResult,
  5→} from '../types/scheduling';
  6→
  7→const SCHEDULES_KEY = 'citedby_monitoring_schedules';
  8→const HISTORY_KEY = 'citedby_scheduled_scan_history';
  9→
 10→export function getSchedules(): MonitoringSchedule[] {
 11→  const raw = localStorage.getItem(SCHEDULES_KEY);
 12→  if (!raw) return [];
 13→  try {
 14→    return JSON.parse(raw) as MonitoringSchedule[];
 15→  } catch {
 16→    return [];
 17→  }
 18→}
 19→
 20→function persistSchedules(schedules: MonitoringSchedule[]): void {
 21→  localStorage.setItem(SCHEDULES_KEY, JSON.stringify(schedules));
 22→}
 23→
 24→export function saveSchedule(
 25→  schedule: Omit<MonitoringSchedule, 'id' | 'createdAt' | 'nextRun' | 'lastRun'>
 26→): MonitoringSchedule {
 27→  const nextRun = computeNextRun(
 28→    schedule.frequency,
 29→    schedule.hour,
 30→    schedule.dayOfWeek,
 31→    schedule.dayOfMonth
 32→  );
 33→
 34→  const newSchedule: MonitoringSchedule = {
 35→    ...schedule,
 36→    id: crypto.randomUUID(),
 37→    createdAt: new Date().toISOString(),
 38→    lastRun: null,
 39→    nextRun,
 40→  };
 41→
 42→  const schedules = getSchedules();
 43→  schedules.push(newSchedule);
 44→  persistSchedules(schedules);
 45→
 46→  return newSchedule;
 47→}
 48→
 49→export function deleteSchedule(id: string): void {
 50→  const schedules = getSchedules().filter((s) => s.id !== id);
 51→  persistSchedules(schedules);
 52→}
 53→
 54→export function togglePause(id: string): MonitoringSchedule | null {
 55→  const schedules = getSchedules();
 56→  const schedule = schedules.find((s) => s.id === id);
 57→  if (!schedule) return null;
 58→
 59→  schedule.paused = !schedule.paused;
 60→
 61→  if (!schedule.paused) {
 62→    schedule.nextRun = computeNextRun(
 63→      schedule.frequency,
 64→      schedule.hour,
 65→      schedule.dayOfWeek,
 66→      schedule.dayOfMonth
 67→    );
 68→  }
 69→
 70→  persistSchedules(schedules);
 71→  return schedule;
 72→}
 73→
 74→export function computeNextRun(
 75→  freq: ScheduleFrequency,
 76→  hour: string,
 77→  dayOfWeek?: number,
 78→  dayOfMonth?: number
 79→): string {
 80→  const [h, m] = hour.split(':').map(Number);
 81→  const now = new Date();
 82→  const next = new Date(now);
 83→
 84→  next.setHours(h, m, 0, 0);
 85→
 86→  if (freq === 'daily') {
 87→    if (next <= now) {
 88→      next.setDate(next.getDate() + 1);
 89→    }
 90→  } else if (freq === 'weekly' && dayOfWeek !== undefined) {
 91→    const currentDay = next.getDay();
 92→    let daysUntil = dayOfWeek - currentDay;
 93→    if (daysUntil < 0 || (daysUntil === 0 && next <= now)) {
 94→      daysUntil += 7;
 95→    }
 96→    next.setDate(next.getDate() + daysUntil);
 97→  } else if (freq === 'monthly' && dayOfMonth !== undefined) {
 98→    next.setDate(dayOfMonth);
 99→    if (next <= now) {
100→      next.setMonth(next.getMonth() + 1);
101→      next.setDate(dayOfMonth);
102→    }
103→  }
104→
105→  return next.toISOString();
106→}
107→
108→export function getScheduledHistory(): ScheduledScanResult[] {
109→  const raw = localStorage.getItem(HISTORY_KEY);
110→  if (!raw) return [];
111→  try {
112→    return JSON.parse(raw) as ScheduledScanResult[];
113→  } catch {
114→    return [];
115→  }
116→}
117→
118→function persistHistory(history: ScheduledScanResult[]): void {
119→  localStorage.setItem(HISTORY_KEY, JSON.stringify(history));
120→}
121→
122→export function checkAndRunPendingScans(): ScheduledScanResult[] {
123→  const now = new Date();
124→  const schedules = getSchedules();
125→  const history = getScheduledHistory();
126→  const newResults: ScheduledScanResult[] = [];
127→
128→  for (const schedule of schedules) {
129→    if (schedule.paused) continue;
130→    if (new Date(schedule.nextRun) > now) continue;
131→
132→    const result: ScheduledScanResult = {
133→      id: crypto.randomUUID(),
134→      scheduleId: schedule.id,
135→      brandName: schedule.brandName,
136→      url: schedule.url,
137→      executedAt: now.toISOString(),
138→      totalCitations: Math.floor(Math.random() * 36) + 5, // 5-40
139→      shareOfVoice: Math.round((Math.random() * 40 + 5) * 100) / 100, // 5-45
140→      trend: Math.round((Math.random() * 40 - 15) * 100) / 100, // -15 to +25
141→      status: 'completed',
142→    };
143→
144→    newResults.push(result);
145→    history.push(result);
146→
147→    schedule.lastRun = now.toISOString();
148→    schedule.nextRun = computeNextRun(
149→      schedule.frequency,
150→      schedule.hour,
151→      schedule.dayOfWeek,
152→      schedule.dayOfMonth
153→    );
154→  }
155→
156→  if (newResults.length > 0) {
157→    persistSchedules(schedules);
158→    persistHistory(history);
159→  }
160→
161→  return newResults;
162→}
