 10→function randomId(): string {
 11→  return Math.random().toString(36).substring(2, 10).toUpperCase();
 12→}
 13→
 14→function randomInRange(min: number, max: number): number {
 15→  return Math.round((min + Math.random() * (max - min)) * 100) / 100;
 16→}
 17→
 18→export function getAdConnections(): AdConnection[] {
 19→  try {
 20→    const raw = localStorage.getItem(STORAGE_KEY);
 21→    return raw ? JSON.parse(raw) : [];
 22→  } catch {
 23→    return [];
 24→  }
 25→}
 26→
 27→function saveConnections(connections: AdConnection[]): void {
 28→  localStorage.setItem(STORAGE_KEY, JSON.stringify(connections));
 29→}
 30→
 31→const MOCK_ACCOUNTS: Record<AdPlatform, { names: string[]; prefix: string }> = {
 32→  'google-ads': {
 33→    names: ['Google Ads - Main', 'Google Ads - Brand', 'Google Ads - Performance'],
 34→    prefix: 'GA',
 35→  },
 36→  'meta-ads': {
 37→    names: ['Meta Business Suite', 'Meta Ads - Primary', 'Meta Ads - Retargeting'],
 38→    prefix: 'MA',
 39→  },
 40→  'linkedin-ads': {
 41→    names: ['LinkedIn Campaign Manager', 'LinkedIn Ads - B2B', 'LinkedIn Ads - Enterprise'],
 42→    prefix: 'LA',
 43→  },
 44→};
 45→
 46→export async function connectAdPlatform(platform: AdPlatform): Promise<AdConnection> {
 47→  await new Promise((resolve) => setTimeout(resolve, 1500));
 48→
 49→  const mock = MOCK_ACCOUNTS[platform];
 50→  const name = mock.names[Math.floor(Math.random() * mock.names.length)];
 51→
 52→  const connection: AdConnection = {
 53→    id: `conn_${randomId()}`,
 54→    platform,
 55→    accountName: name,
 56→    accountId: `${mock.prefix}-${Math.floor(100000000 + Math.random() * 900000000)}`,
 57→    connectedAt: new Date().toISOString(),
 58→    status: 'connected',
 59→  };
 60→
 61→  const connections = getAdConnections();
 62→  connections.push(connection);
 63→  saveConnections(connections);
 64→
 65→  return connection;
 66→}
 67→
 68→export function disconnectAdPlatform(id: string): void {
 69→  const connections = getAdConnections().map((conn) =>
 70→    conn.id === id ? { ...conn, status: 'disconnected' as const } : conn
 71→  );
 72→  saveConnections(connections);
 73→}
 74→
 75→export function generateRetargetingOpportunities(
 76→  citations: Array<{ url?: string; query: string; engine: string }>
 77→): RetargetingOpportunity[] {
 78→  return citations.map((citation) => {
 79→    const pixelId = `CB-${randomId()}`;
 80→    const url =
 81→      citation.url ||
 82→      `https://www.example.com/${citation.query.toLowerCase().replace(/\s+/g, '-')}`;
 83→    const estimatedAudience = Math.floor(500 + Math.random() * 14500);
 84→
 85→    const pixelCode = `<!-- CitedBy.ai Retargeting Pixel -->
 86→<script>
 87→  !function(c,b,r){c.cbq=c.cbq||[];var s=b.createElement('script');
 88→  s.async=1;s.src='https://t.citedby.ai/pixel.js';
 89→  b.head.appendChild(s)}(window,document);
 90→  cbq('init','${pixelId}');
 91→  cbq('track','AIVisitor',{source:'${citation.engine}',query:'${citation.query.replace(/'/g, "\\'")}'});
 92→</script>`;
 93→
 94→    return {
 95→      id: `opp_${randomId()}`,
 96→      url,
 97→      engine: citation.engine,
 98→      query: citation.query,
 99→      estimatedAudience,
100→      pixelCode,
101→    };
102→  });
103→}
104→
105→const PLATFORM_RATES: Record<AdPlatform, { cpc: [number, number]; cpm: [number, number] }> = {
106→  'google-ads': { cpc: [0.35, 0.85], cpm: [3.5, 8.0] },
107→  'meta-ads': { cpc: [0.25, 0.65], cpm: [5.0, 12.0] },
108→  'linkedin-ads': { cpc: [1.5, 4.5], cpm: [15.0, 35.0] },
109→};
110→
111→export function estimateBudget(
112→  platform: AdPlatform,
113→  dailyBudget: number,
114→  audienceSize: number
115→): BudgetEstimate {
116→  const rates = PLATFORM_RATES[platform];
117→  const cpc = randomInRange(rates.cpc[0], rates.cpc[1]);
118→  const cpm = randomInRange(rates.cpm[0], rates.cpm[1]);
119→
120→  const estimatedReach = Math.round(dailyBudget / (cpm / 1000));
121→  const estimatedClicks = Math.round(dailyBudget / cpc);
122→
123→  return {
124→    platform,
125→    dailyBudget,
126→    estimatedReach,
127→    estimatedClicks,
128→    cpc,
129→    cpm,
130→  };
131→}
132→
133→export function exportAudienceCSV(opportunities: RetargetingOpportunity[]): string {
134→  const headers = 'URL,Engine,Query,Estimated Audience,Pixel ID';
135→  const rows = opportunities.map((opp) => {
136→    const pixelIdMatch = opp.pixelCode.match(/cbq\('init','(CB-[A-Z0-9]+)'\)/);
137→    const pixelId = pixelIdMatch ? pixelIdMatch[1] : '';
138→    const escapedQuery = `"${opp.query.replace(/"/g, '""')}"`;
139→    return `${opp.url},${opp.engine},${escapedQuery},${opp.estimatedAudience},${pixelId}`;
140→  });
141→
142→  return [headers, ...rows].join('\n');
143→}
144→
145→export function downloadCSV(csv: string, filename: string): void {
146→  const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
147→  const url = URL.createObjectURL(blob);
148→  const link = document.createElement('a');
149→  link.href = url;
150→  link.setAttribute('download', filename);
151→  document.body.appendChild(link);
152→  link.click();
153→  document.body.removeChild(link);
154→  URL.revokeObjectURL(url);
155→}
