                      <span className="text-[10px] text-gray-500">{engine.sentiment.neutral}%</span>
                      <span className="text-[10px] text-red-400">{engine.sentiment.negative}%</span>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>

          {/* ── Citations Table ── */}
          <div className="ninja-card p-6 mb-8">
            <div className="flex items-center justify-between mb-6">
              <div>
                <h3 className="text-lg font-bold text-white">Citations recentes</h3>
                <p className="text-xs text-gray-500 mt-0.5">{result.citations.length} citations detectees</p>
              </div>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full">
                <thead>
                  <tr className="border-b border-white/[0.06]">
                    <th className="text-left text-xs font-medium text-gray-500 uppercase tracking-wider pb-3 pr-4">Moteur</th>
                    <th className="text-left text-xs font-medium text-gray-500 uppercase tracking-wider pb-3 pr-4">Requete</th>
                    <th className="text-center text-xs font-medium text-gray-500 uppercase tracking-wider pb-3 pr-4">Position</th>
                    <th className="text-left text-xs font-medium text-gray-500 uppercase tracking-wider pb-3 pr-4">Date</th>
                    <th className="text-center text-xs font-medium text-gray-500 uppercase tracking-wider pb-3 pr-4">Sentiment</th>
                    <th className="text-center text-xs font-medium text-gray-500 uppercase tracking-wider pb-3">Confiance</th>
                  </tr>
                </thead>
                <tbody>
                  {result.citations.slice(0, 15).map((citation) => {
                    const sentCfg = SENTIMENT_CONFIG[citation.sentiment];
                    const SentIcon = sentCfg.icon;
                    return (
                      <tr key={citation.id} className="border-b border-white/[0.03] hover:bg-white/[0.02] transition-colors">
                        <td className="py-3.5 pr-4">
                          <span className={`text-xs font-medium px-2 py-1 rounded-md border ${ENGINE_BG[citation.engine]}`}>
                            {citation.engine}
                          </span>
                        </td>
                        <td className="py-3.5 pr-4">
                          <div className="max-w-xs">
                            <p className="text-sm text-gray-200 truncate">{citation.query}</p>
                            <p className="text-xs text-gray-600 truncate mt-0.5">{citation.snippet}</p>
                          </div>
                        </td>
                        <td className="py-3.5 pr-4 text-center">
                          <span className={`text-sm font-bold ${citation.position <= 2 ? 'text-emerald-400' : citation.position <= 4 ? 'text-amber-400' : 'text-gray-400'}`}>
                            #{citation.position}
                          </span>
                        </td>
                        <td className="py-3.5 pr-4">
                          <span className="text-xs text-gray-400">{new Date(citation.date).toLocaleDateString('fr-FR')}</span>
                        </td>
                        <td className="py-3.5 pr-4 text-center">
                          <span className={`inline-flex items-center gap-1 text-xs px-2 py-1 rounded-md ${sentCfg.bg} ${sentCfg.color}`}>
                            <SentIcon size={10} />
                            {sentCfg.label}
                          </span>
                        </td>
                        <td className="py-3.5 text-center">
                          <span className="text-xs text-gray-400">{citation.confidence}%</span>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </div>

          {/* ── Competitor Comparison ── */}
          <div className="ninja-card p-6 mb-8">
            <div className="flex items-center justify-between mb-6">
              <div>
                <h3 className="text-lg font-bold text-white">Comparaison concurrentielle</h3>
                <p className="text-xs text-gray-500 mt-0.5">Votre marque vs les concurrents detectes</p>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4">
              {/* Your brand card */}
              <div className="p-4 rounded-xl bg-gradient-to-br from-purple-500/10 to-violet-600/10 border border-purple-500/20">
                <div className="flex items-center gap-2 mb-3">
                  <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-purple-500 to-violet-600 flex items-center justify-center">
                    <Sparkles size={14} className="text-white" />
                  </div>
                  <div>
                    <p className="text-sm font-bold text-white truncate">{result.brandName}</p>
                    <p className="text-[10px] text-purple-400">Votre marque</p>
                  </div>
                </div>
                <div className="space-y-2">
                  <div className="flex justify-between">
                    <span className="text-xs text-gray-500">Citations</span>
                    <span className="text-xs font-bold text-white">{result.totalCitations}</span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-xs text-gray-500">SoV</span>
                    <span className="text-xs font-bold text-purple-400">{result.shareOfVoice}%</span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-xs text-gray-500">Tendance</span>
                    <span className={`text-xs font-bold ${result.trend >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>
                      {result.trend >= 0 ? '+' : ''}{result.trend}%
                    </span>
                  </div>
                </div>
              </div>

              {/* Competitor cards */}
              {result.competitors.map((comp) => (
                <div key={comp.name} className="p-4 rounded-xl bg-white/[0.02] border border-white/[0.06] hover:bg-white/[0.04] transition-colors">
                  <div className="flex items-center gap-2 mb-3">
                    <div className="w-8 h-8 rounded-lg bg-white/[0.06] flex items-center justify-center">
                      <span className="text-xs font-bold text-gray-400">{comp.name.charAt(0)}</span>
                    </div>
                    <div>
                      <p className="text-sm font-bold text-gray-200 truncate">{comp.name}</p>
                      <span className={`text-[10px] px-1.5 py-0.5 rounded border ${ENGINE_BG[comp.dominantEngine]}`}>
                        {comp.dominantEngine}
                      </span>
                    </div>
                  </div>
                  <div className="space-y-2">
                    <div className="flex justify-between">
                      <span className="text-xs text-gray-500">Citations</span>
                      <span className="text-xs font-bold text-gray-300">{comp.totalCitations}</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-xs text-gray-500">SoV</span>
                      <span className="text-xs font-bold text-gray-300">{comp.shareOfVoice}%</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-xs text-gray-500">Tendance</span>
                      <span className={`text-xs font-bold ${comp.trend >= 0 ? 'text-emerald-400' : 'text-red-400'}`}>
                        {comp.trend >= 0 ? '+' : ''}{comp.trend}%
                      </span>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* ── Summary & Recommendations ── */}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
            {/* Summary */}
            <div className="ninja-card p-6">
              <h3 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
                <BarChart3 size={18} className="text-purple-400" />
                Resume de l'analyse
              </h3>
              <p className="text-sm text-gray-400 leading-relaxed">{result.summary}</p>
            </div>

            {/* Recommendations */}
            <div className="ninja-card p-6">
              <h3 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
                <Sparkles size={18} className="text-purple-400" />
                Recommandations
              </h3>
              <div className="space-y-3">
                {result.recommendations.map((rec, i) => (
                  <div key={i} className="flex items-start gap-3">
                    <div className="w-6 h-6 rounded-full bg-purple-500/10 border border-purple-500/20 flex items-center justify-center shrink-0 mt-0.5">
                      <span className="text-xs font-bold text-purple-400">{i + 1}</span>
                    </div>
                    <p className="text-sm text-gray-400 leading-relaxed">{rec}</p>
                  </div>
                ))}
              </div>
            </div>
          </div>

          {/* ── CTA to other tools ── */}
          <div className="ninja-card p-6 bg-gradient-to-r from-purple-500/5 to-violet-600/5 border-purple-500/10">
            <div className="flex flex-col md:flex-row items-center justify-between gap-4">
              <div className="flex items-center gap-4">
                <div className="p-3 rounded-xl bg-purple-500/10">
                  <Zap size={20} className="text-purple-400" />
                </div>
                <div>
                  <h3 className="text-base font-bold text-white">Ameliorez votre visibilite IA</h3>
                  <p className="text-sm text-gray-500">Utilisez nos outils generatifs pour optimiser votre citabilite</p>
                </div>
              </div>
              <button
                onClick={() => onNavigate('generative-tools')}
                className="flex items-center gap-2 px-5 py-2.5 bg-gradient-to-r from-purple-600 to-violet-600 hover:from-purple-500 hover:to-violet-500 text-white text-sm font-medium rounded-xl transition-all shadow-lg shadow-purple-900/30 whitespace-nowrap"
              >
                Voir les outils <ArrowRight size={14} />
              </button>
            </div>
          </div>
        </>
      )}

      {/* ── Retargeting Tab ── */}
      {resultTab === 'retargeting' && (
        <>
          {/* Ad Platform Connection Cards */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8">
            {(['google-ads', 'meta-ads', 'linkedin-ads'] as AdPlatform[]).map((platform) => {
              const info = PLATFORM_INFO[platform];
              const connection = adConnections.find(
                (c) => c.platform === platform && c.status === 'connected'
              );
              const isConnecting = connectingPlatform === platform;

              return (
                <div key={platform} className="ninja-card p-5">
                  <div className="flex items-center gap-3 mb-4">
                    <div className={`w-10 h-10 rounded-xl ${info.bg} border flex items-center justify-center`}>
                      <span className={`text-sm font-bold ${info.color}`}>{info.icon}</span>
                    </div>
                    <div>
                      <h4 className="text-sm font-bold text-white">{info.name}</h4>
                      {connection ? (
                        <p className="text-[10px] text-emerald-400">{connection.accountName}</p>
                      ) : (
                        <p className="text-[10px] text-gray-500">Non connecte</p>
                      )}
                    </div>
                  </div>

                  {connection ? (
                    <div className="space-y-3">
                      <div className="flex justify-between text-xs">
                        <span className="text-gray-500">Account ID</span>
                        <span className="text-gray-300 font-mono text-[10px]">{connection.accountId}</span>
                      </div>
                      <div className="flex justify-between text-xs">
                        <span className="text-gray-500">Statut</span>
                        <span className="text-emerald-400 flex items-center gap-1">
                          <span className="w-1.5 h-1.5 rounded-full bg-emerald-400" />
                          Connecte
                        </span>
                      </div>
                      <button
                        onClick={() => handleDisconnectPlatform(connection.id)}
                        className="w-full mt-2 py-2 text-xs font-medium rounded-lg bg-red-500/10 text-red-400 hover:bg-red-500/20 transition-all border border-red-500/20"
                      >
                        Deconnecter
                      </button>
                    </div>
                  ) : (
                    <button
                      onClick={() => handleConnectPlatform(platform)}
                      disabled={isConnecting}
                      className="w-full py-2.5 text-sm font-medium rounded-xl bg-gradient-to-r from-purple-600 to-violet-600 hover:from-purple-500 hover:to-violet-500 text-white transition-all shadow-lg shadow-purple-900/30 disabled:opacity-50 flex items-center justify-center gap-2"
                    >
                      {isConnecting ? (
                        <>
                          <Loader2 size={14} className="animate-spin" />
                          Connexion...
                        </>
                      ) : (
                        'Connecter'
                      )}
                    </button>
                  )}
                </div>
              );
            })}
          </div>

          {/* Retargeting Opportunities Table */}
          <div className="ninja-card p-6 mb-8">
            <div className="flex items-center justify-between mb-6">
              <div>
                <h3 className="text-lg font-bold text-white">URLs citees = opportunites de retargeting</h3>
                <p className="text-xs text-gray-500 mt-0.5">{retargetingOpps.length} opportunites detectees</p>
              </div>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full">
                <thead>
                  <tr className="border-b border-white/[0.06]">
                    <th className="text-left text-xs font-medium text-gray-500 uppercase tracking-wider pb-3 pr-4">URL</th>
                    <th className="text-left text-xs font-medium text-gray-500 uppercase tracking-wider pb-3 pr-4">Moteur</th>
                    <th className="text-right text-xs font-medium text-gray-500 uppercase tracking-wider pb-3 pr-4">Audience estimee</th>
                    <th className="text-center text-xs font-medium text-gray-500 uppercase tracking-wider pb-3">Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {retargetingOpps.slice(0, 15).map((opp) => (
                    <React.Fragment key={opp.id}>
                      <tr className="border-b border-white/[0.03] hover:bg-white/[0.02] transition-colors">
                        <td className="py-3.5 pr-4">
                          <div className="max-w-xs">
                            <p className="text-sm text-gray-200 truncate" title={opp.url}>{opp.url}</p>
                            <p className="text-xs text-gray-600 truncate mt-0.5">{opp.query}</p>
                          </div>
                        </td>
                        <td className="py-3.5 pr-4">
                          <span className={`text-xs font-medium px-2 py-1 rounded-md border ${
                            ENGINE_BG[opp.engine as AIEngine] || 'bg-gray-500/10 text-gray-400 border-gray-500/20'
                          }`}>
                            {opp.engine}
                          </span>
                        </td>
                        <td className="py-3.5 pr-4 text-right">
                          <span className="text-sm font-bold text-white">{opp.estimatedAudience.toLocaleString('fr-FR')}</span>
                        </td>
                        <td className="py-3.5 text-center">
                          <div className="flex items-center justify-center gap-2">
                            <button
                              onClick={() => handleCopyPixel(opp.id, opp.pixelCode)}
                              className={`text-xs font-medium px-3 py-1.5 rounded-lg transition-all ${
                                copiedPixel === opp.id
                                  ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20'
                                  : 'bg-purple-500/10 text-purple-400 border border-purple-500/20 hover:bg-purple-500/20'
                              }`}
                            >
                              {copiedPixel === opp.id ? 'Copie !' : 'Copier le pixel'}
                            </button>
                            <button
                              onClick={() => setExpandedPixel(expandedPixel === opp.id ? null : opp.id)}
                              className="text-xs text-gray-400 hover:text-white transition-colors px-2 py-1.5 rounded-lg bg-white/[0.04] hover:bg-white/[0.08]"
                            >
                              {expandedPixel === opp.id ? 'Masquer' : 'Voir code'}
                            </button>
                          </div>
                        </td>
                      </tr>
                      {expandedPixel === opp.id && (
                        <tr>
                          <td colSpan={4} className="pb-4 pt-1 px-2">
                            <pre className="bg-[#0a0a0a] border border-white/[0.06] rounded-xl p-4 text-xs text-gray-400 overflow-x-auto font-mono leading-relaxed">
                              {opp.pixelCode}
                            </pre>
                          </td>
                        </tr>
                      )}
                    </React.Fragment>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          {/* Budget Estimator */}
          <div className="ninja-card p-6 mb-8">
            <h3 className="text-lg font-bold text-white mb-1">Estimateur budget</h3>
            <p className="text-xs text-gray-500 mb-6">Estimez la portee de vos campagnes de retargeting IA</p>

            {/* Platform selector */}
            <div className="flex gap-3 mb-6">
              {(['google-ads', 'meta-ads', 'linkedin-ads'] as AdPlatform[]).map((platform) => {
                const info = PLATFORM_INFO[platform];
                return (
                  <button
                    key={platform}
                    onClick={() => setBudgetPlatform(platform)}
                    className={`flex-1 py-2.5 rounded-xl text-sm font-medium transition-all duration-200 flex items-center justify-center gap-2 ${
                      budgetPlatform === platform
                        ? 'bg-gradient-to-r from-purple-600 to-violet-600 text-white shadow-lg shadow-purple-900/30'
                        : 'bg-white/[0.04] border border-white/[0.08] text-gray-400 hover:text-white hover:bg-white/[0.06]'
                    }`}
                  >
                    <span className={budgetPlatform === platform ? 'text-white' : info.color}>{info.icon}</span>
                    {info.name}
                  </button>
                );
              })}
            </div>

            {/* Budget slider */}
            <div className="mb-8">
              <div className="flex items-center justify-between mb-3">
                <label className="text-sm font-medium text-gray-300">Budget quotidien</label>
                <span className="text-lg font-bold bg-gradient-to-r from-purple-400 to-violet-400 bg-clip-text text-transparent">
                  {dailyBudget} EUR/jour
                </span>
              </div>
              <input
                type="range"
                min={10}
                max={500}
                step={5}
                value={dailyBudget}
                onChange={(e) => setDailyBudget(Number(e.target.value))}
                className="w-full h-2 bg-white/[0.06] rounded-full appearance-none cursor-pointer accent-purple-500"
              />
              <div className="flex justify-between mt-1.5">
                <span className="text-[10px] text-gray-600">10 EUR</span>
                <span className="text-[10px] text-gray-600">500 EUR</span>
              </div>
            </div>

            {/* KPI Cards */}
            <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
              <div className="p-4 rounded-xl bg-white/[0.02] border border-white/[0.06]">
                <span className="text-xs text-gray-500 block mb-1">Portee estimee</span>
                <span className="text-xl font-bold text-white">{budgetEstimate.estimatedReach.toLocaleString('fr-FR')}</span>
                <span className="text-[10px] text-gray-500 block mt-0.5">impressions/jour</span>
              </div>
              <div className="p-4 rounded-xl bg-white/[0.02] border border-white/[0.06]">
                <span className="text-xs text-gray-500 block mb-1">Clics estimes</span>
                <span className="text-xl font-bold text-white">{budgetEstimate.estimatedClicks.toLocaleString('fr-FR')}</span>
                <span className="text-[10px] text-gray-500 block mt-0.5">clics/jour</span>
              </div>
              <div className="p-4 rounded-xl bg-white/[0.02] border border-white/[0.06]">
                <span className="text-xs text-gray-500 block mb-1">CPC</span>
                <span className="text-xl font-bold text-emerald-400">{budgetEstimate.cpc.toFixed(2)} EUR</span>
                <span className="text-[10px] text-gray-500 block mt-0.5">cout par clic</span>
              </div>
              <div className="p-4 rounded-xl bg-white/[0.02] border border-white/[0.06]">
                <span className="text-xs text-gray-500 block mb-1">CPM</span>
                <span className="text-xl font-bold text-blue-400">{budgetEstimate.cpm.toFixed(2)} EUR</span>
                <span className="text-[10px] text-gray-500 block mt-0.5">cout pour 1000 imp.</span>
              </div>
            </div>
          </div>

          {/* Export CSV Button */}
          <div className="flex justify-end mb-8">
            <button
              onClick={handleExportCSV}
              disabled={retargetingOpps.length === 0}
              className="flex items-center gap-2 px-5 py-2.5 bg-gradient-to-r from-purple-600 to-violet-600 hover:from-purple-500 hover:to-violet-500 disabled:opacity-40 disabled:cursor-not-allowed text-white text-sm font-medium rounded-xl transition-all shadow-lg shadow-purple-900/30"
            >
              <Download size={16} />
              Exporter CSV ({retargetingOpps.length} opportunites)
            </button>
          </div>
        </>
      )}
    </div>
  );
};

export default AiMonitoring;

